class Solution(object):
    def uniquePaths(self, grid):
        MOD = 10**9 + 7
        m, n = len(grid), len(grid[0])

        # go[i][j][0] = landing cell when entering (i,j) moving right
        # go[i][j][1] = landing cell when entering (i,j) moving down
        go = [[[None, None] for _ in range(n)] for _ in range(m)]

        for i in range(m - 1, -1, -1):
            for j in range(n - 1, -1, -1):
                if grid[i][j] == 0:
                    go[i][j][0] = (i, j)
                    go[i][j][1] = (i, j)
                else:
                    # entering right -> deflect down to (i+1, j)
                    if i + 1 < m:
                        go[i][j][0] = go[i + 1][j][1]
                    else:
                        go[i][j][0] = None
                    # entering down -> deflect right to (i, j+1)
                    if j + 1 < n:
                        go[i][j][1] = go[i][j + 1][0]
                    else:
                        go[i][j][1] = None

        dp = [[0] * n for _ in range(m)]
        dp[0][0] = 1

        for i in range(m):
            for j in range(n):
                if dp[i][j] == 0:
                    continue
                if j + 1 < n:
                    dest = go[i][j + 1][0]
                    if dest is not None:
                        dp[dest[0]][dest[1]] = (dp[dest[0]][dest[1]] + dp[i][j]) % MOD
                if i + 1 < m:
                    dest = go[i + 1][j][1]
                    if dest is not None:
                        dp[dest[0]][dest[1]] = (dp[dest[0]][dest[1]] + dp[i][j]) % MOD

        return dp[m - 1][n - 1]
